export enum Gender {
  MALE = 'MALE',
  FEMALE = 'FEMALE'
}

export interface Player {
  id: string;
  name: string;
  gender: Gender;
}

export interface Team {
  player1: Player;
  player2: Player;
}

export interface Match {
  id: string;
  teamA: Team;
  teamB: Team;
  type: MatchType;
  timestamp: number;
}

export enum MatchType {
  RANDOM = '一般隨機',
  MENS_DOUBLES = '男雙',
  WOMENS_DOUBLES = '女雙',
  MIXED_DOUBLES = '混雙'
}

