import { Player, Team, Match, MatchType, Gender } from '../types';

// Fisher-Yates Shuffle
const shuffle = <T,>(array: T[]): T[] => {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
};

export const generateMatch = (
  players: Player[],
  type: MatchType
): { match: Match | null; error: string | null } => {
  let pool = [...players];
  let teamA: Team;
  let teamB: Team;

  if (players.length < 4) {
    return { match: null, error: '人數不足，至少需要 4 人才能開始比賽！' };
  }

  // Filter based on game type
  if (type === MatchType.MENS_DOUBLES) {
    pool = pool.filter(p => p.gender === Gender.MALE);
    if (pool.length < 4) return { match: null, error: '男生人數不足 4 人，無法進行男雙！' };
  } else if (type === MatchType.WOMENS_DOUBLES) {
    pool = pool.filter(p => p.gender === Gender.FEMALE);
    if (pool.length < 4) return { match: null, error: '女生人數不足 4 人，無法進行女雙！' };
  }

  // Shuffle the pool
  const shuffled = shuffle(pool);

  if (type === MatchType.MIXED_DOUBLES) {
    const males = shuffle(players.filter(p => p.gender === Gender.MALE));
    const females = shuffle(players.filter(p => p.gender === Gender.FEMALE));

    if (males.length < 2 || females.length < 2) {
      return { match: null, error: '混雙需要至少 2 男 2 女！' };
    }

    // Team A: M1 + F1, Team B: M2 + F2
    teamA = { player1: males[0], player2: females[0] };
    teamB = { player1: males[1], player2: females[1] };
  } else {
    // Standard Random or Single Gender modes (already filtered)
    teamA = { player1: shuffled[0], player2: shuffled[1] };
    teamB = { player1: shuffled[2], player2: shuffled[3] };
  }

  const newMatch: Match = {
    id: Date.now().toString(),
    teamA,
    teamB,
    type,
    timestamp: Date.now(),
  };

  return { match: newMatch, error: null };
};

import React from 'react';
