interface PlayerCardProps {
  player: Player;
  onDelete?: (id: string) => void;
  size?: 'sm' | 'md' | 'lg';
}

const PlayerCard: React.FC<PlayerCardProps> = ({ player, onDelete, size = 'md' }) => {
  const isMale = player.gender === Gender.MALE;
  const colorClass = isMale ? COLORS.male : COLORS.female;

  const sizeClasses = {
    sm: 'px-2 py-1 text-xs',
    md: 'px-3 py-1.5 text-sm',
    lg: 'px-4 py-2 text-base'
