  return (
    <div className={`
      relative group flex items-center gap-2 rounded-full border-2 
      ${colorClass} ${sizeClasses[size]} 
      shadow-sm transition-all duration-300 hover:scale-105 hover:shadow-md cursor-default select-none
    `}>
      <div className={`
        rounded-full p-1 
        ${isMale ? 'bg-blue-200' : 'bg-pink-200'}
