  primary: 'bg-emerald-400 hover:bg-emerald-500',
  secondary: 'bg-amber-300 hover:bg-amber-400',
  accent: 'bg-purple-400 hover:bg-purple-500',
};

export const ICONS = {
  User: <User size={20} />,
  Users: <Users size={20} />,
  Zap: <Zap size={20} />,
  Trophy: <Trophy size={20} />
};

// Empty initial players as requested
export const INITIAL_PLAYERS = [];

import { Player, Team, Match, MatchType, Gender } from '../types';

// Fisher-Yates Shuffle
const shuffle = <T,>(array: T[]): T[] => {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
};

export const generateMatches = (
  players: Player[],
  type: MatchType
): { matches: Match[]; waiting: Player[]; error: string | null } => {
  let pool = [...players];
  const matches: Match[] = [];

  if (players.length < 4) {
    return { matches: [], waiting: players, error: '人數不足，至少需要 4 人才能開始比賽！' };
  }

  // Filter based on game type first
  let filteredPool = [...pool];
  if (type === MatchType.MENS_DOUBLES) {
    filteredPool = pool.filter(p => p.gender === Gender.MALE);
    if (filteredPool.length < 4) return { matches: [], waiting: players, error: '男生人數不足 4 人，無法進行男雙！' };
  } else if (type === MatchType.WOMENS_DOUBLES) {
    filteredPool = pool.filter(p => p.gender === Gender.FEMALE);
    if (filteredPool.length < 4) return { matches: [], waiting: players, error: '女生人數不足 4 人，無法進行女雙！' };
  }

  // Logic for Mixed Doubles
  if (type === MatchType.MIXED_DOUBLES) {
    let males = shuffle(players.filter(p => p.gender === Gender.MALE));
    let females = shuffle(players.filter(p => p.gender === Gender.FEMALE));

    while (males.length >= 2 && females.length >= 2) {
      // Create a match
      const m1 = males.pop()!;
      const m2 = males.pop()!;
      const f1 = females.pop()!;
      const f2 = females.pop()!;

      const teamA: Team = { player1: m1, player2: f1 };
      const teamB: Team = { player1: m2, player2: f2 };

      matches.push({
        id: Date.now().toString() + Math.random().toString(),
        teamA,
        teamB,
        type,
        timestamp: Date.now(),
      });
    }

    // Remaining players are waiting
    // We only return waiting players from the relevant gender pools if strict, 
    // or just everyone who didn't play. 
    // Usually implies everyone else waits.
    const waiting = [...males, ...females, ...players.filter(p => p.gender !== Gender.MALE && p.gender !== Gender.FEMALE)]; // catch-all? actually just remaining m/f

    // Also need to add back players who were filtered out initially if we want to show them as waiting?
    // But for mixed, usually we only care about the pool. 
    // Let's simplified: waiting is everyone not in a match.
    const playingIds = new Set(matches.flatMap(m => [m.teamA.player1.id, m.teamA.player2.id, m.teamB.player1.id, m.teamB.player2.id]));
    const allWaiting = players.filter(p => !playingIds.has(p.id));

    if (matches.length === 0) {
       return { matches: [], waiting: players, error: '混雙需要至少 2 男 2 女！' };
    }

    return { matches, waiting: allWaiting, error: null };
  }

  // Logic for Standard Random or Single Gender
  // Shuffle the filtered pool
  let processingPool = shuffle(filteredPool);

  while (processingPool.length >= 4) {
    const p1 = processingPool.pop()!;
    const p2 = processingPool.pop()!;
    const p3 = processingPool.pop()!;
    const p4 = processingPool.pop()!;

    const teamA: Team = { player1: p1, player2: p2 };
    const teamB: Team = { player1: p3, player2: p4 };

    matches.push({
        id: Date.now().toString() + Math.random().toString(),
        teamA,
        teamB,
        type,
        timestamp: Date.now(),
    });
  }

  // Calculate waiting
  const playingIds = new Set(matches.flatMap(m => [m.teamA.player1.id, m.teamA.player2.id, m.teamB.player1.id, m.teamB.player2.id]));
  const waiting = players.filter(p => !playingIds.has(p.id));

  return { matches, waiting, error: null };
};

